import Mathlib.Tactic.Classic
import Mathlib.Tactic.Int.Basic

-- Define the array type and its properties
def intArray (n : ℕ) : Type := Array ℕ n

lemma intArray_get_def (a : intArray n) (i : ℕ) : a i = some x => i < n ∧ x = a.item i

-- Define the SelectionSort function and its property
def SelectionSort (a : intArray n) : intArray n :=
{ carrier := λ i, begin
    have i_lt_n : i < n, from le_total_iff.mpr (lt_total a.length i)
    have i_lt_n_1 : i < n - 1, from lt_of_le_of_lt i_lt_n (le_succ i_lt_n)
    let mut min := i
    for j in (i + 1)..n do
      have j_lt_n : j < n, from le_total_iff.mpr (lt_total a.length j)
      have j_lt_min_or_min_eq_j : j ≤ min ∨ min = j, by { cases min; simp [min] }
      have j_lt_min : j < min, by { cases min; simp [min]; assume h : j = min, contradiction }
      have a_j_lt_a_min : a j < a min, by { cases min; simp [min] }
      have min_updated : min := j, from le_trans j_lt_min a_j_lt_a_min
      have temp := a i
      have a_i_eq_a_min : a i = a min, by { cases min; simp [min] }
      have a_min_eq_temp : a min = temp, by { cases min; simp [min] }
      have i_eq_min : i = min, by { cases min; simp [min] }
      have min_updated_eq_temp : min = temp, by { cases min; simp [min] }
      replace min := min_updated
      replace a.item i := a.item min
      replace a.item min := temp
    end,
    -- Check the property after sorting
    have property_after_sorting : ∀ i, a i ≤ a (i+1), begin
      induction i with i i ih, { intros; simp [i_lt_n_1] },
      { intros; simp [i_lt_n]; assume h : a i > a (i+1),
        have j_lt_i : i+1 < n, by { cases n; simp [n] };
        have j_lt_i_1 : i+1 < i, by { contradiction };
        have j_lt_i_or_i_eq_j : i <= i+1 ∨ i = i+1, by { cases i; simp [i] };
        have j_lt_min : i+1 < min, by { cases min; simp [min]; assume h : i+1 = min, contradiction };
        have a_i_lt_a_min : a i < a min, by { cases min; simp [min] };
        have a_min_lt_a_i : a min < a i, by { cases min; simp [min] };
        have a_i_lt_a_j : a i < a (i+1), by { cases i+1; simp [i+1] };
        have a_j_lt_a_min : a (i+1) < a min, by { cases min; simp [min] };
        have a_min_lt_a_j : a min < a (i+1), by { cases min; simp [min] };
        have j_lt_min_or_min_eq_j : j ≤ min ∨ min = j, by { cases min; simp [min] };
        have j_lt_min : j < min, by { cases min; simp [min]; assume h : j = min, contradiction };
        have a_j_eq_a_min : a j = a min, by { cases min; simp [min] };
        have a_min_eq_temp : a min = temp, by { cases min; simp [min] };
        have temp_eq_a_i : temp = a i, by { cases i; simp [i] };
        have temp_eq_a_j : temp = a j, by { cases j; simp [j] };
        have a_i_eq_temp : a i = temp, by { cases i; simp [i] };
        have a_j_eq_temp : a j = temp, by { cases j; simp [j] };
        have temp_lt_a_min : temp < a min, by { cases min; simp [min] };
        have temp_lt_a_j : temp < a j, by { cases j; simp [j] };
        have temp_lt_a_i : temp < a i, by { cases i; simp [i] };
        have a_i_lt_temp : a i < temp, by { cases i; simp [i] };
        have a_min_lt_temp : a min < temp, by { cases min; simp [min] };
        have temp_lt_a_i_or_a_i_eq_temp : temp ≤ a i ∨ a i = temp, by { cases a_i_lt_temp; cases a_i_eq_temp };
        have temp_lt_a_j_or_a_j_eq_temp : temp ≤ a j ∨ a j = temp, by { cases a_j_lt_temp; cases a_j_eq_temp };
        have a_i_lt_a_j : a i < a j, by { cases i; cases j; simp [i, j] };
        have temp_lt_a_i_or_a_i_eq_temp : temp ≤ a i ∨ a i = temp, by { cases a_i_lt_temp; cases a_i_eq_temp };
        have temp_lt_a_j_or_a_j_eq_temp : temp ≤ a j ∨ a j = temp, by { cases a_j_lt_temp; cases a_j_eq_temp };
        have temp_lt_a_min : temp < a min, by { cases min; simp [min] };
        have a_min_lt_temp : a min < temp, by { cases min; simp [min] };
        have temp_lt_a_i : temp < a i, by { cases i; simp [i] };
        have temp_lt_a_j : temp < a j, by { cases j; simp [j] };
        have temp_lt_temp : temp < temp, by absurd temp_eq_a_i;
        have temp_lt_temp : temp < temp, by absurd temp_eq_a_j;
        have temp_lt_a_min : temp < a min, by absurd temp_eq_a_min;
        have temp_lt_a_i : temp < a i, by absurd temp_eq_a_i;
        have temp_lt_a_j : temp < a j, by absurd temp_eq_a_j;
        have temp_lt_min : temp < min, by absurd temp_eq_min;
        have a_i_lt_temp : a i < temp, by absurd a_i_eq_temp;
        have a_j_lt_temp : a j < temp, by absurd a_j_eq_temp;
        have a_min_lt_temp : a min < temp, by absurd a_min_eq_temp;
        have a_i_lt_a_j : a i < a j, by absurd a_i_eq_a_j;
        have a_j_lt_a_i : a j < a i, by absurd a_j_eq_a_i;
        have a_min_lt_a_i : a min < a i, by absurd a_min_eq_a_i;
        have a_min_lt_a_j : a min < a j, by absurd a_min_eq_a_j;
        have a_i_lt_temp_or_temp_eq_a_i : a i ≤ temp ∨ temp = a i, by { cases temp_lt_a_i; cases temp_eq_a_i };
        have a_j_lt_temp_or_temp_eq_a_j : a j ≤ temp ∨ temp = a j, by { cases temp_lt_a_j; cases temp_eq_a_j };
        have a_i_lt_min_or_min_eq_i : a i ≤ min ∨ min = i, by { cases min; simp [min] };
        have a_j_lt_min_or_min_eq_j : a j ≤ min ∨ min = j, by { cases min; simp [min] };
        have a_i_lt_min_or_min_eq_i : a i ≤ min ∨ min = i, from or_trans (a_i_lt_min) (or_iff_left a_i_eq_min) (a_min_eq_i);
        have a_j_lt_min_or_min_eq_j : a j ≤ min ∨ min = j, from or_trans (a_j_lt_min) (or_iff_left a_j_eq_min) (a_min_eq_j);
