  Id_MCDC_1 : string,
  -- ... other fields ...
}

defstruct Velocity_Mode VLMODE [Id_MCDC_47 : int16, Id_MCDC_48 : int16, ...]

def fopen (filename : string) : option FILE

def valid_free (f : option FILE) : Prop :=
 match f with
 | none => true
 | some file => all (fun i => file.Id_MCDC_i != null)
 end

def init () : Unit :=
 do
 let main_result := main()
 let _ := CHECK (init (main()), ∀ (f : option FILE), valid_free f)
 let _ := CHECK (init (main()), ∀ (f : option FILE), valid_deref f)
 let _ := CHECK (init (main()), ∀ (f : option FILE), valid_memtrack f)
 main_result
