#print "main"

open Lean Nat Bool

import Mathlib

namespace Jain_4_2

inductive init : Nat → Prop
| main : init 0

def main : init :=
{ x := 0, y := 0, z := 0, loop : ∀ n, x + y + z ≠ 1 }

instance : init.{x = 0, y = 0, z = 0} :=
{ x := 0, y := 0, z := 0, loop := λ n, by { cases n with d hd; simp [hd] } }

